Hi, thanks for posting your question. The `runAll` function takes an array of objects, which define how to access the DB. The host member is the IP or the DNS address of the DB, you can also specify port and password. If you specify multiple DBs, the state will be sharded across the databases using `sid` as key.

```javascript
var d = require('durable');
var m = d.m, s = d.s, c = d.c;

d.ruleset('a1', {
        whenAll: [ m.amount.eq(200) ],
        run: function(c) {
            console.log(c.m.amount);
        }
    },
    function (host) {
        host.post('a1', {id: 1, sid: 1, amount: 200});
    }
);

d.runAll([{host: 'dnshostname'}]);
```

