	if ts=="dell_s55":
		li["look_for_keys"]=True
	ssh=ConnectHandler(**li)
	ssh.enable()
	if ts=="dell_n2000":
		ret=DellN2000(ssh,ip)
	elif typ=="dell_force10":
		ret=DellForce10(ssh,ip)
	elif typ=="dell_powerconnect":
		ret=DellPowerConnect(ssh,ip)
	return(ret)

