[CT_table - L29](https://github.com/scanny/python-pptx/blob/a2cfe775b7e77c4cbfa47cae4c9912ecc52dd5da/pptx/oxml/shapes/table.py#L29)

```python
class CT_Table(BaseOxmlElement):
    """
    ``<a:tbl>`` custom element class
    """
    tblPr = ZeroOrOne('a:tblPr', successors=('a:tblGrid', 'a:tr'))
    tblGrid = OneAndOnlyOne('a:tblGrid')
    tr = ZeroOrMore('a:tr', successors=())

    def add_tr(self, height):
        """
        Return a reference to a newly created <a:tr> child element having its
        ``h`` attribute set to *height*.
        """
        return self._add_tr(h=height)
```

so perhaps I should solve it like: 
```python
class CT_Bookmark(BaseOxmlElement):
    """The ``<w:bookmarkStart>`` element"""
    name = ZeroOrMore('w:name', ST_String, successors())
    id = ZeroOrMore('w:id', ST_RelationshipId, , successors('w:name'))

    def add_id(self):
        return self._add_id(id=self.next_id)

    def add_name(self, name):
        return self._add_name(name=name)

    @property
    def _next_id(self):
        """
        The first ``w:id`` unused by a ``<w:bookmarkStart>`` element, starting at
        1 and filling any gaps in numbering between existing ``<w:bookmarkStart>``
        elements.
        """
        bmrk_id_strs = self.xpath('.//w:bookmarkStart/@w:id')
        bmrk_ids = [int(bmrk_id_str) for bmrk_id_str in bmrk_id_strs]
        for num in range(1, len(bmrk_ids)+2):
            if num not in bmrk_ids:
                break
        return str(num)

    @property
    def is_closed(self):
        """
        The `is_closed` property of the :class:`CT_BookmarkRange` object is
        used to determine whether there is already a bookmarkEnd element in
        the document containing the same bookmark id. If this is the case, the
        bookmark is closed if not, the bookmark is open.
        """
        root_element = self.getroottree().getroot()
        matching_bookmarkEnds = root_element.xpath(
            './/w:bookmarkEnd[@w:id=\'%s\']' % self.bmrk_id
        )
        if not matching_bookmarkEnds:
            return False
        return True
```

